export const INDEXER_NETWORK_TARGETS = ["mainnet", "local"] as const;

export type IndexerNetworkTarget = (typeof INDEXER_NETWORK_TARGETS)[number];

export interface IndexerTargetConfig {
  canisterIds: string[];
  network: {
    target: IndexerNetworkTarget;
    local: {
      host: string;
      port: number;
    };
  };
}

export const INDEXER_TARGET_CONFIG = {
  canisterIds: ["txyno-ch777-77776-aaaaq-cai"],
  network: {
    target: "local",
    local: {
      host: "localhost",
      port: 8000
    }
  }
} satisfies IndexerTargetConfig;

import { fileURLToPath } from "node:url";

import {
  INDEXER_NETWORK_TARGETS,
  INDEXER_TARGET_CONFIG,
  type IndexerTargetConfig
} from "./indexer.config.js";

export interface IndexerConfig {
  host: string;
  port: number;
  databasePath: string;
  websocketPath: string;
  ingestion: IndexerTargetConfig;
  factoryCanisterId?: string;
  icHost: string;
  fastPollIntervalMs: number;
  slowPollIntervalMs: number;
  pricePollIntervalMs: number;
}

export interface IndexerConfigOverrides {
  host?: string;
  port?: number;
  databasePath?: string;
  websocketPath?: string;
  ingestion?: IndexerTargetConfig;
  factoryCanisterId?: string;
  fastPollIntervalMs?: number;
  slowPollIntervalMs?: number;
  pricePollIntervalMs?: number;
}

const DEFAULT_DATABASE_PATH = fileURLToPath(
  new URL("../data/indexer.sqlite", import.meta.url)
);
const BASE32_ALPHABET = "abcdefghijklmnopqrstuvwxyz234567";
const CRC32_TABLE = buildCrc32Table();

function parseNumber(value: string | undefined, fallback: number) {
  if (!value) {
    return fallback;
  }

  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

function buildCrc32Table() {
  const table = new Uint32Array(256);

  for (let index = 0; index < table.length; index += 1) {
    let value = index;

    for (let bit = 0; bit < 8; bit += 1) {
      value = (value & 1) === 0 ? value >>> 1 : (value >>> 1) ^ 0xedb88320;
    }

    table[index] = value >>> 0;
  }

  return table;
}

function computeCrc32(bytes: Uint8Array) {
  let crc = 0xffffffff;

  for (const byte of bytes) {
    crc = CRC32_TABLE[(crc ^ byte) & 0xff] ^ (crc >>> 8);
  }

  return (crc ^ 0xffffffff) >>> 0;
}

function decodeBase32(input: string) {
  const output: number[] = [];
  let buffer = 0;
  let bits = 0;

  for (const character of input) {
    const value = BASE32_ALPHABET.indexOf(character);

    if (value === -1) {
      return null;
    }

    buffer = (buffer << 5) | value;
    bits += 5;

    while (bits >= 8) {
      bits -= 8;
      output.push((buffer >>> bits) & 0xff);
    }
  }

  if (bits > 0 && (buffer & ((1 << bits) - 1)) !== 0) {
    return null;
  }

  return Uint8Array.from(output);
}

function isValidCanisterId(value: string) {
  if (!/^[a-z2-7-]+$/.test(value)) {
    return false;
  }

  const groups = value.split("-");
  if (groups.length === 0 || groups.some((group) => group.length === 0 || group.length > 5)) {
    return false;
  }

  if (groups.slice(0, -1).some((group) => group.length !== 5)) {
    return false;
  }

  const decoded = decodeBase32(groups.join(""));
  if (decoded === null || decoded.length < 4) {
    return false;
  }

  const checksum =
    (decoded[0] << 24) | (decoded[1] << 16) | (decoded[2] << 8) | decoded[3];
  const principal = decoded.slice(4);

  return (checksum >>> 0) === computeCrc32(principal);
}

function validateTargetConfig(config: IndexerTargetConfig) {
  const errors: string[] = [];

  if (!Array.isArray(config.canisterIds) || config.canisterIds.length === 0) {
    errors.push("Indexer ingestion config must include at least one canister ID.");
  }

  for (const [index, canisterId] of config.canisterIds.entries()) {
    if (typeof canisterId !== "string" || !isValidCanisterId(canisterId.trim())) {
      errors.push(
        `Indexer ingestion config canisterIds[${index}] must be a valid canister ID. Received: ${JSON.stringify(canisterId)}.`
      );
    }
  }

  if (!INDEXER_NETWORK_TARGETS.includes(config.network.target)) {
    errors.push(
      `Indexer ingestion config network.target must be one of ${INDEXER_NETWORK_TARGETS.map((target) => JSON.stringify(target)).join(", ")}. Received: ${JSON.stringify(config.network.target)}.`
    );
  }

  if (config.network.target === "local") {
    if (typeof config.network.local.host !== "string" || config.network.local.host.trim() === "") {
      errors.push(
        'Indexer ingestion config network.local.host must be set when network.target is "local".'
      );
    }

    if (!Number.isInteger(config.network.local.port) || config.network.local.port <= 0) {
      errors.push(
        'Indexer ingestion config network.local.port must be set to a positive integer when network.target is "local".'
      );
    }
  }

  if (errors.length > 0) {
    throw new Error(`Invalid indexer ingestion config:\n- ${errors.join("\n- ")}`);
  }
}

function cloneTargetConfig(config: IndexerTargetConfig): IndexerTargetConfig {
  return {
    canisterIds: [...config.canisterIds],
    network: {
      target: config.network.target,
      local: {
        host: config.network.local.host,
        port: config.network.local.port
      }
    }
  };
}

function resolveIcHost(config: IndexerTargetConfig) {
  if (config.network.target === "mainnet") {
    return "https://ic0.app";
  }

  return `http://${config.network.local.host}:${config.network.local.port}`;
}

export function resolveIndexerConfig(
  env: NodeJS.ProcessEnv = process.env,
  overrides: IndexerConfigOverrides = {}
): IndexerConfig {
  const ingestion = cloneTargetConfig(overrides.ingestion ?? INDEXER_TARGET_CONFIG);
  validateTargetConfig(ingestion);

  return {
    host: overrides.host ?? env.HOST ?? "0.0.0.0",
    port: overrides.port ?? parseNumber(env.PORT, 3001),
    databasePath: overrides.databasePath ?? env.INDEXER_DB_PATH ?? DEFAULT_DATABASE_PATH,
    websocketPath: overrides.websocketPath ?? env.INDEXER_WS_PATH ?? "/ws/events",
    ingestion,
    factoryCanisterId:
      overrides.factoryCanisterId ?? env.INDEXER_FACTORY_CANISTER_ID ?? undefined,
    icHost: resolveIcHost(ingestion),
    fastPollIntervalMs:
      overrides.fastPollIntervalMs ?? parseNumber(env.INDEXER_FAST_POLL_INTERVAL_MS, 15_000),
    slowPollIntervalMs:
      overrides.slowPollIntervalMs ?? parseNumber(env.INDEXER_SLOW_POLL_INTERVAL_MS, 300_000),
    pricePollIntervalMs:
      overrides.pricePollIntervalMs ?? parseNumber(env.INDEXER_PRICE_POLL_INTERVAL_MS, 60_000)
  };
}

import { describe, expect, it } from "vitest";

import { resolveIndexerConfig } from "../src/config.js";
import { INDEXER_TARGET_CONFIG } from "../src/indexer.config.js";
import { buildServer } from "../src/server.js";

describe("indexer config", () => {
  it("uses the dedicated target config file as the default ingestion source", () => {
    const config = resolveIndexerConfig({});

    expect(config.ingestion).toEqual(INDEXER_TARGET_CONFIG);
    expect(config.icHost).toBe("http://localhost:8000");
  });

  it("derives the IC host from the configured network target", () => {
    const config = resolveIndexerConfig(
      {},
      {
        ingestion: {
          canisterIds: ["aaaaa-aa"],
          network: {
            target: "mainnet",
            local: {
              host: "127.0.0.1",
              port: 4943
            }
          }
        }
      }
    );

    expect(config.ingestion.canisterIds).toEqual(["aaaaa-aa"]);
    expect(config.icHost).toBe("https://ic0.app");
  });

  it("fails when the canister list is empty", () => {
    expect(() =>
      resolveIndexerConfig(
        {},
        {
          ingestion: {
            canisterIds: [],
            network: {
              target: "local",
              local: {
                host: "localhost",
                port: 8000
              }
            }
          }
        }
      )
    ).toThrowError("Indexer ingestion config must include at least one canister ID.");
  });

  it("fails when a canister ID format is invalid", () => {
    expect(() =>
      resolveIndexerConfig(
        {},
        {
          ingestion: {
            canisterIds: ["not-a-canister-id"],
            network: {
              target: "local",
              local: {
                host: "localhost",
                port: 8000
              }
            }
          }
        }
      )
    ).toThrowError("Indexer ingestion config canisterIds[0] must be a valid canister ID.");
  });

  it("fails when the network target is unsupported", () => {
    expect(() =>
      resolveIndexerConfig(
        {},
        {
          ingestion: {
            canisterIds: ["aaaaa-aa"],
            network: {
              target: "staging" as never,
              local: {
                host: "localhost",
                port: 8000
              }
            }
          }
        }
      )
    ).toThrowError('Indexer ingestion config network.target must be one of "mainnet", "local".');
  });

  it("fails when local mode is missing the local host or port", () => {
    expect(() =>
      resolveIndexerConfig(
        {},
        {
          ingestion: {
            canisterIds: ["aaaaa-aa"],
            network: {
              target: "local",
              local: {
                host: "",
                port: 0
              }
            }
          }
        }
      )
    ).toThrowError('network.local.host must be set when network.target is "local".');
  });

  it("fails server startup immediately when the ingestion config is invalid", () => {
    expect(() =>
      buildServer({
        config: {
          ingestion: {
            canisterIds: [],
            network: {
              target: "local",
              local: {
                host: "localhost",
                port: 8000
              }
            }
          }
        }
      })
    ).toThrowError("Invalid indexer ingestion config:");
  });
});

