 34	const DEFAULT_DATABASE_PATH = fileURLToPath(
 35	  new URL("../data/indexer.sqlite", import.meta.url)
 36	);
 37	const BASE32_ALPHABET = "abcdefghijklmnopqrstuvwxyz234567";
 38	const CRC32_TABLE = buildCrc32Table();
 39	
 40	function parseNumber(value: string | undefined, fallback: number) {
 41	  if (!value) {
 42	    return fallback;
 43	  }
 44	
 45	  const parsed = Number(value);
 46	  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
 47	}
 48	
 49	function parseOptionalInteger(value: string | undefined) {
 50	  if (value === undefined) {
 51	    return undefined;
 52	  }
 53	
 54	  return Number(value);
 55	}
 56	
 57	function buildCrc32Table() {
 58	  const table = new Uint32Array(256);
 59	
 60	  for (let index = 0; index < table.length; index += 1) {
 61	    let value = index;
 62	
 63	    for (let bit = 0; bit < 8; bit += 1) {
 64	      value = (value & 1) === 0 ? value >>> 1 : (value >>> 1) ^ 0xedb88320;
 65	    }
 66	
 67	    table[index] = value >>> 0;
 68	  }
 69	
 70	  return table;
 71	}
 72	
 73	function computeCrc32(bytes: Uint8Array) {
 74	  let crc = 0xffffffff;
 75	
 76	  for (const byte of bytes) {
 77	    crc = CRC32_TABLE[(crc ^ byte) & 0xff] ^ (crc >>> 8);
 78	  }
 79	
 80	  return (crc ^ 0xffffffff) >>> 0;
 81	}
 82	
 83	function decodeBase32(input: string) {
 84	  const output: number[] = [];
 85	  let buffer = 0;
 86	  let bits = 0;
 87	
 88	  for (const character of input) {
 89	    const value = BASE32_ALPHABET.indexOf(character);
 90	
 91	    if (value === -1) {
 92	      return null;
 93	    }
 94	
 95	    buffer = (buffer << 5) | value;
 96	    bits += 5;
 97	
 98	    while (bits >= 8) {
 99	      bits -= 8;
100	      output.push((buffer >>> bits) & 0xff);
101	    }
102	  }
103	
104	  if (bits > 0 && (buffer & ((1 << bits) - 1)) !== 0) {
105	    return null;
106	  }
107	
108	  return Uint8Array.from(output);
109	}
110	
111	function isValidCanisterId(value: string) {
112	  if (!/^[a-z2-7-]+$/.test(value)) {
113	    return false;
114	  }
115	
116	  const groups = value.split("-");
117	  if (groups.length === 0 || groups.some((group) => group.length === 0 || group.length > 5)) {
118	    return false;
119	  }
120	
121	  if (groups.slice(0, -1).some((group) => group.length !== 5)) {
122	    return false;
123	  }
124	
125	  const decoded = decodeBase32(groups.join(""));
126	  if (decoded === null || decoded.length < 4) {
127	    return false;
128	  }
129	
130	  const checksum =
131	    (decoded[0] << 24) | (decoded[1] << 16) | (decoded[2] << 8) | decoded[3];
132	  const principal = decoded.slice(4);
133	
134	  return (checksum >>> 0) === computeCrc32(principal);
135	}
