137	function validateTargetConfig(config: IndexerTargetConfig) {
138	  const errors: string[] = [];
139	
140	  if (!Array.isArray(config.canisterIds) || config.canisterIds.length === 0) {
141	    errors.push("Indexer ingestion config must include at least one canister ID.");
142	  }
143	
144	  for (const [index, canisterId] of config.canisterIds.entries()) {
145	    if (typeof canisterId !== "string" || !isValidCanisterId(canisterId.trim())) {
146	      errors.push(
147	        `Indexer ingestion config canisterIds[${index}] must be a valid canister ID. Received: ${JSON.stringify(canisterId)}.`
148	      );
149	    }
150	  }
151	
152	  if (!INDEXER_NETWORK_TARGETS.includes(config.network.target)) {
153	    errors.push(
154	      `Indexer ingestion config network.target must be one of ${INDEXER_NETWORK_TARGETS.map((target) => JSON.stringify(target)).join(", ")}. Received: ${JSON.stringify(config.network.target)}.`
155	    );
156	  }
157	
158	  if (config.network.target === "local") {
159	    if (typeof config.network.local.host !== "string" || config.network.local.host.trim() === "") {
160	      errors.push(
161	        'Indexer ingestion config network.local.host must be set when network.target is "local".'
162	      );
163	    }
164	
165	    if (!Number.isInteger(config.network.local.port) || config.network.local.port <= 0) {
166	      errors.push(
167	        'Indexer ingestion config network.local.port must be set to a positive integer when network.target is "local".'
168	      );
169	    }
170	  }
171	
172	  if (errors.length > 0) {
173	    throw new Error(`Invalid indexer ingestion config:\n- ${errors.join("\n- ")}`);
174	  }
175	}
176	
177	function cloneTargetConfig(config: IndexerTargetConfig): IndexerTargetConfig {
178	  return {
179	    canisterIds: [...config.canisterIds],
180	    network: {
181	      target: config.network.target,
182	      local: {
183	        host: config.network.local.host,
184	        port: config.network.local.port
185	      }
186	    }
187	  };
188	}
189	
190	function applyEnvIngestionOverrides(
191	  config: IndexerTargetConfig,
192	  env: NodeJS.ProcessEnv
193	): IndexerTargetConfig {
194	  const nextConfig = cloneTargetConfig(config);
195	
196	  if (env.INDEXER_INGESTION_NETWORK_TARGET !== undefined) {
197	    nextConfig.network.target =
198	      env.INDEXER_INGESTION_NETWORK_TARGET as IndexerTargetConfig["network"]["target"];
199	  }
200	
201	  if (env.INDEXER_INGESTION_LOCAL_HOST !== undefined) {
202	    nextConfig.network.local.host = env.INDEXER_INGESTION_LOCAL_HOST;
203	  }
204	
205	  const localPort = parseOptionalInteger(env.INDEXER_INGESTION_LOCAL_PORT);
206	
207	  if (localPort !== undefined) {
208	    nextConfig.network.local.port = localPort;
209	  }
210	
211	  return nextConfig;
212	}
213	
214	function resolveIcHost(config: IndexerTargetConfig) {
215	  if (config.network.target === "mainnet") {
216	    return "https://ic0.app";
217	  }
218	
219	  return `http://${config.network.local.host}:${config.network.local.port}`;
220	}
221	
222	export function resolveIndexerConfig(
223	  env: NodeJS.ProcessEnv = process.env,
224	  overrides: IndexerConfigOverrides = {}
225	): IndexerConfig {
226	  const ingestion = applyEnvIngestionOverrides(
227	    overrides.ingestion ?? INDEXER_TARGET_CONFIG,
228	    env
229	  );
230	  validateTargetConfig(ingestion);
231	
232	  return {
233	    host: overrides.host ?? env.HOST ?? "0.0.0.0",
234	    port: overrides.port ?? parseNumber(env.PORT, 3001),
235	    databasePath: overrides.databasePath ?? env.INDEXER_DB_PATH ?? DEFAULT_DATABASE_PATH,
236	    websocketPath: overrides.websocketPath ?? env.INDEXER_WS_PATH ?? "/ws/events",
237	    ingestion,
238	    factoryCanisterId:
239	      overrides.factoryCanisterId ?? env.INDEXER_FACTORY_CANISTER_ID ?? undefined,
240	    icHost: resolveIcHost(ingestion),
241	    fastPollIntervalMs:
242	      overrides.fastPollIntervalMs ?? parseNumber(env.INDEXER_FAST_POLL_INTERVAL_MS, 15_000),
243	    slowPollIntervalMs:
244	      overrides.slowPollIntervalMs ?? parseNumber(env.INDEXER_SLOW_POLL_INTERVAL_MS, 300_000),
245	    pricePollIntervalMs:
246	      overrides.pricePollIntervalMs ?? parseNumber(env.INDEXER_PRICE_POLL_INTERVAL_MS, 60_000)
247	  };
248	}
